// ═══ GEO HELPERS ══════════════════════════════════════════════
function haversineKm(a,b,c,d){const R=6371,t=x=>x*Math.PI/180,dL=t(c-a),dO=t(d-b),e=Math.sin(dL/2)**2+Math.cos(t(a))*Math.cos(t(c))*Math.sin(dO/2)**2;return R*2*Math.atan2(Math.sqrt(e),Math.sqrt(1-e));}
function fmtDist(km){return km<1?Math.round(km*1000)+"m":km.toFixed(1)+"km";}
const rc  = s=>RAINBOW[(s||"a").charCodeAt(0)%RAINBOW.length];
const rc2 = s=>RAINBOW[((s||"a").charCodeAt(0)+2)%RAINBOW.length];

