// ═══ HOOKS ════════════════════════════════════════════════════
function useVH() {
  const [, forceUpdate] = useState(0);
  useEffect(() => {
    const set = () => {
      const h = window.innerHeight;
      document.documentElement.style.setProperty('--vh', (h * 0.01) + 'px');
      document.documentElement.style.setProperty('--app-h', h + 'px');
      // force all consumers to re-render with new size
      forceUpdate(n => n + 1);
    };
    set();
    window.addEventListener('resize', set);
    const onOri = () => { setTimeout(set, 80); setTimeout(set, 300); };
    window.addEventListener('orientationchange', onOri);
    // also listen for visual viewport (keyboard open/close on mobile)
    if (window.visualViewport) {
      window.visualViewport.addEventListener('resize', set);
    }
    return () => {
      window.removeEventListener('resize', set);
      window.removeEventListener('orientationchange', onOri);
      if (window.visualViewport) window.visualViewport.removeEventListener('resize', set);
    };
  }, []);
  return window.innerHeight;
}

// ═══ UI PRIMITIVES ════════════════════════════════════════════
function Av({ init="?", size=40, img=null, online=false, rainbow=false }) {
  const [imgFailed, setImgFailed] = useState(false);
  // reset if img prop changes
  useEffect(() => { setImgFailed(false); }, [img]);

  const isNum = typeof size === "number";
  const cssSz = isNum ? size + "px" : size;

  const showImg = img && !imgFailed;

  const inner = showImg
    ? <img src={img}
        style={{width:cssSz,height:cssSz,minWidth:cssSz,minHeight:cssSz,
          borderRadius:"50%",objectFit:"cover",display:"block",flexShrink:0}}
        onError={() => setImgFailed(true)} />
    : <div style={{width:cssSz,height:cssSz,minWidth:cssSz,minHeight:cssSz,borderRadius:"50%",
        background:`linear-gradient(135deg,${rc(init)},${rc2(init)})`,
        display:"flex",alignItems:"center",justifyContent:"center",
        fontSize:`calc(${cssSz} * 0.34)`,fontWeight:700,color:"#fff",
        fontFamily:"'Orbitron',monospace",flexShrink:0}}>
        {(init||"?").slice(0,2).toUpperCase()}
      </div>;

  return (
    <div style={{position:"relative",display:"inline-flex",flexShrink:0}}>
      {rainbow
        ? <div style={{background:`conic-gradient(${RAINBOW.join(",")})`,padding:"2.5px",borderRadius:"50%",display:"inline-flex"}}>
            <div style={{background:"#07070f",padding:"2px",borderRadius:"50%",display:"inline-flex"}}>{inner}</div>
          </div>
        : inner}
      {online && <div style={{position:"absolute",bottom:1,right:1,
        width:`calc(${cssSz} * 0.22)`,height:`calc(${cssSz} * 0.22)`,
        minWidth:7,minHeight:7,borderRadius:"50%",
        background:"#00E676",border:"2px solid #07070f",boxShadow:"0 0 6px #00E676"}} />}
    </div>
  );
}

function Tog({ on, set }) {
  return (
    <div onClick={() => set(v=>!v)} role="switch" aria-checked={on}
      style={{width:48,height:27,borderRadius:14,flexShrink:0,cursor:"pointer",transition:"all .3s",
        background: on ? "linear-gradient(90deg,#AA00FF,#FF0055)" : "#ffffff18",
        border:`1.5px solid ${on?"#AA00FF55":"#ffffff1a"}`,
        boxShadow: on ? "0 0 14px #AA00FF55" : "none", position:"relative"}}>
      <div style={{width:21,height:21,borderRadius:"50%",background:"#fff",position:"absolute",
        top:2,left:on?23:2,transition:"left .3s",boxShadow:"0 2px 6px #00000055"}} />
    </div>
  );
}

function Btn({ children, onClick, color="#AA00FF", style={}, disabled=false, outline=false }) {
  return (
    <button onClick={onClick} disabled={disabled}
      style={{background: disabled?"#ffffff12": outline?"transparent":`linear-gradient(135deg,${color},${color}cc)`,
        border:`1.5px solid ${disabled?"#ffffff15":color+"55"}`,borderRadius:14,padding:"13px 18px",
        color: disabled?"#ffffff44": outline?color:"#fff",fontWeight:700,fontFamily:"'Orbitron',monospace",
        fontSize:"clamp(11px,3vw,13px)",letterSpacing:.5,
        boxShadow: disabled||outline?"none":`0 4px 20px ${color}33`,
        cursor:disabled?"not-allowed":"pointer",transition:"all .2s",...style}}>
      {children}
    </button>
  );
}

function Sheet({ children, onClose, title="" }) {
  return (
    <div style={{position:"fixed",inset:0,background:"#000000cc",zIndex:200,display:"flex",alignItems:"flex-end"}}
      onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} className="fu"
        style={{background:"#0e0e1e",borderRadius:"22px 22px 0 0",width:"100%",maxWidth:480,margin:"0 auto",
          border:"1.5px solid #ffffff0a",maxHeight:"92dvh",overflowY:"auto",boxShadow:"0 -8px 40px #00000088"}}>
        <div style={{width:36,height:4,background:"#ffffff22",borderRadius:2,margin:"14px auto 0"}} />
        {title && <h3 style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(12px,3.5vw,14px)",
          letterSpacing:1,color:"#fff",padding:"12px 20px 10px"}}>{title}</h3>}
        <div style={{padding: title?"0 18px 28px":"18px 18px 28px"}}>{children}</div>
      </div>
    </div>
  );
}


