// ═══ PROFILE ══════════════════════════════════════════════════
function ProfileView({ me, myProfile, posts, onTicket, isAdmin, onSettings, notifs, onEdit, onFollowers, onFollowing, onSearch, followCount, followerCount }) {
  const [pt,setPt]=useState("posts");
  if (!me) return null;
  const filtered = pt==="posts"?posts:posts.filter(p=>p.ev);
  const totalPosts = posts.length;
  return (
    <div>
      <div style={{padding:"0 14px clamp(12px,3.5vw,16px)"}}>
        {/* Header row: avatar + stats */}
        <div style={{display:"flex",gap:"clamp(10px,3vw,14px)",alignItems:"center",marginBottom:13}}>
          <div onClick={onEdit} style={{cursor:"pointer",flexShrink:0}}>
            <Av init={me.av||"EU"} size="clamp(64px,19vw,80px)"
              img={myProfile.avatarUrl||me.img||null} rainbow />
          </div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:2,flexWrap:"wrap"}}>
              <span style={{fontWeight:700,fontSize:"clamp(14px,4vw,17px)",color:"#fff"}}>{myProfile.displayName||me.username}</span>
              {isAdmin && <span style={{fontSize:9,background:"#FFD70020",border:"1.5px solid #FFD70040",borderRadius:6,padding:"2px 7px",color:"#FFD700",fontFamily:"'Orbitron',monospace"}}>ADMIN</span>}
            </div>
            <div style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffffaa",marginBottom:9,wordBreak:"break-word"}}>
              {myProfile.bio||me.bio}
              {myProfile.website&&<div style={{color:"#00B4FF",marginTop:2}}>{myProfile.website}</div>}
            </div>
            {/* Stats: posts / seguidores / seguindo */}
            <div style={{display:"flex",gap:"clamp(10px,3vw,18px)"}}>
              <div style={{textAlign:"center"}}>
                <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,16px)",color:"#fff"}}>{totalPosts}</div>
                <div style={{fontSize:"clamp(9px,2.5vw,11px)",color:"#ffffff77"}}>posts</div>
              </div>
              <div style={{textAlign:"center",cursor:"pointer"}} onClick={onFollowers}>
                <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,16px)",color:"#fff"}}>{followerCount}</div>
                <div style={{fontSize:"clamp(9px,2.5vw,11px)",color:"#ffffff77"}}>seguidores</div>
              </div>
              <div style={{textAlign:"center",cursor:"pointer"}} onClick={onFollowing}>
                <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,16px)",color:"#fff"}}>{followCount}</div>
                <div style={{fontSize:"clamp(9px,2.5vw,11px)",color:"#ffffff77"}}>seguindo</div>
              </div>
            </div>
          </div>
        </div>
        {/* Action buttons */}
        <div style={{display:"flex",gap:8,marginBottom:notifs.length>0?10:0}}>
          <button onClick={onEdit}
            style={{flex:1,background:"linear-gradient(135deg,#AA00FF22,#FF005522)",border:"1.5px solid #AA00FF44",borderRadius:10,padding:"clamp(8px,2.5vw,10px)",color:"#fff",fontSize:"clamp(11px,3vw,13px)",fontWeight:600,display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
            ✏️ Editar Perfil
          </button>
          <button onClick={onSearch}
            style={{background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:10,padding:"clamp(8px,2.5vw,10px) 14px",color:"#ffffffcc",fontSize:"clamp(14px,4vw,17px)"}}>🔍</button>
          <button onClick={onSettings}
            style={{background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:10,padding:"clamp(8px,2.5vw,10px) 14px",color:"#ffffffcc",fontSize:"clamp(14px,4vw,17px)"}}>⚙️</button>
        </div>
        {notifs.length>0 && (
          <div style={{background:"#FF005512",border:"1.5px solid #FF005533",borderRadius:9,padding:"9px 12px"}}>
            <p style={{fontSize:"clamp(8px,2.2vw,10px)",fontFamily:"'Orbitron',monospace",color:"#FF0055",marginBottom:3}}>NOTIFICAÇÕES</p>
            {notifs.slice(-3).map(n=><p key={n.id} style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffffcc",marginTop:2}}>⚠ {n.txt}</p>)}
          </div>
        )}
      </div>
      {/* Tabs */}
      <div style={{display:"flex",borderBottom:"1.5px solid #ffffff0d"}}>
        {["posts","eventos"].map(t=>(
          <button key={t} onClick={()=>setPt(t)} style={{flex:1,background:"none",color:pt===t?"#fff":"#ffffff55",
            padding:"clamp(8px,2.5vw,11px) 0",fontSize:"clamp(9px,2.5vw,11px)",fontFamily:"'Orbitron',monospace",letterSpacing:1,
            borderBottom:pt===t?"2.5px solid #AA00FF":"2.5px solid transparent",transition:"all .2s"}}>
            {t.toUpperCase()}
          </button>
        ))}
      </div>
      {filtered.length===0
        ? <div style={{textAlign:"center",padding:"clamp(32px,8vw,52px) 20px",color:"#ffffff44",fontSize:"clamp(12px,3.5vw,14px)"}}>
            {pt==="posts"?"Nenhuma publicação ainda.":"Nenhum evento ainda."}
          </div>
        : <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:1.5,marginTop:1.5}}>
            {filtered.map(p=>(
              <div key={p.id} onClick={()=>p.tk&&onTicket(p.tk)} style={{aspectRatio:"1",overflow:"hidden",position:"relative",cursor:p.tk?"pointer":"default"}}>
                <img src={p.img} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={e=>e.target.style.display="none"} />
                {p.ev && <div style={{position:"absolute",top:4,right:4,fontSize:"clamp(10px,3vw,13px)"}}>🎫</div>}
                {p.T && <div style={{position:"absolute",top:4,left:4,fontSize:9,background:"#FF005599",borderRadius:4,padding:"2px 5px",fontFamily:"'Orbitron',monospace",color:"#fff",fontWeight:700}}>T</div>}
              </div>
            ))}
          </div>
      }
    </div>
  );
}

// ═══ DM LIST ══════════════════════════════════════════════════
function DMList({ chats, nearby, onOpen }) {
  return (
    <div style={{padding:"0 12px"}}>
      <h3 style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(11px,3vw,13px)",letterSpacing:2,marginBottom:14,color:"#fff"}}>✉ MENSAGENS</h3>
      {nearby.filter(u=>!u.bl).slice(0,8).map(u=>{
        const msgs=chats[u.uid]||[],last=msgs[msgs.length-1];
        return (
          <div key={u.id} onClick={()=>onOpen(u)}
            style={{display:"flex",alignItems:"center",gap:"clamp(9px,3vw,13px)",padding:"clamp(10px,3vw,13px) 0",borderBottom:"1px solid #ffffff0a",cursor:"pointer"}}>
            <Av init={u.av} size="clamp(42px,11vw,50px)" img={u.p1} online={u.on} />
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:2}}>
                <span style={{fontWeight:700,fontSize:"clamp(12px,3.5vw,15px)",color:"#fff"}}>{u.sn}</span>
                <span style={{fontSize:"clamp(9px,2.5vw,11px)",color:"#ffffff55"}}>{u.dist}</span>
              </div>
              <span style={{fontSize:"clamp(11px,3vw,13px)",color:"#ffffffaa",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",display:"block"}}>
                {last ? last.once ? "🔥 Foto única" : last.img ? "📷 Foto" : last.text : "Inicie a conversa…"}
              </span>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ═══ CHAT ═════════════════════════════════════════════════════
// ── Componente de mensagem de foto única ──────────────────────
function OncePhoto({ msg, isMine }) {
  const [state, setState] = useState(msg.viewed ? "viewed" : "ready");
  // "ready" = bolha fechada | "open" = contagem regressiva | "viewed" = expirado
  const [secs,  setSecs]  = useState(20);
  const timerRef = useRef(null);
  const [, forceUpdate] = useState(0);

  const open = () => {
    if (state !== "ready") return;
    setState("open");
    setSecs(20);
    // marca como visto no objeto original para não reabrir
    msg.viewed = true;
    timerRef.current = setInterval(() => {
      setSecs(s => {
        if (s <= 1) {
          clearInterval(timerRef.current);
          setState("viewed");
          forceUpdate(n=>n+1);
          return 0;
        }
        return s - 1;
      });
    }, 1000);
  };

  useEffect(() => () => clearInterval(timerRef.current), []);

  const bubbleBg = isMine
    ? "linear-gradient(135deg,#AA00FF,#FF0055)"
    : "#ffffff12";

  // ── ESTADO: já expirou ──
  if (state === "viewed") {
    return (
      <div style={{background: bubbleBg, borderRadius: isMine?"18px 18px 5px 18px":"18px 18px 18px 5px",
        padding:"10px 14px", display:"flex", alignItems:"center", gap:8, opacity:.6}}>
        <span style={{fontSize:18}}>🔥</span>
        <span style={{fontSize:"clamp(11px,3vw,13px)", color:"#fff"}}>Foto expirada</span>
      </div>
    );
  }

  // ── ESTADO: contagem regressiva ──
  if (state === "open") {
    return (
      <div style={{position:"relative", borderRadius: isMine?"18px 18px 5px 18px":"18px 18px 18px 5px",
        overflow:"hidden", maxWidth:"min(220px,65vw)"}}>
        <img src={msg.img} alt="" style={{width:"100%", display:"block",
          borderRadius: isMine?"18px 18px 5px 18px":"18px 18px 18px 5px"}} />
        {/* countdown overlay */}
        <div style={{position:"absolute", top:8, right:8,
          background:"#000000cc", backdropFilter:"blur(6px)",
          borderRadius:20, padding:"4px 10px",
          display:"flex", alignItems:"center", gap:5}}>
          <span style={{fontSize:12}}>🔥</span>
          <span style={{fontFamily:"'Orbitron',monospace", fontSize:13,
            fontWeight:700, color: secs<=5?"#FF0055":"#fff"}}>{secs}s</span>
        </div>
        {/* progress ring */}
        <svg style={{position:"absolute",top:6,right:6,width:32,height:32,transform:"rotate(-90deg)"}} viewBox="0 0 32 32">
          <circle cx="16" cy="16" r="13" fill="none" stroke="#ffffff22" strokeWidth="3"/>
          <circle cx="16" cy="16" r="13" fill="none"
            stroke={secs<=5?"#FF0055":"#AA00FF"} strokeWidth="3"
            strokeDasharray={`${2*Math.PI*13}`}
            strokeDashoffset={`${2*Math.PI*13*(1 - secs/20)}`}
            strokeLinecap="round" style={{transition:"stroke-dashoffset 1s linear"}}/>
        </svg>
      </div>
    );
  }

  // ── ESTADO: pronto para abrir ──
  return (
    <div onClick={isMine ? undefined : open}
      style={{background: bubbleBg,
        borderRadius: isMine?"18px 18px 5px 18px":"18px 18px 18px 5px",
        padding:"12px 16px", display:"flex", alignItems:"center", gap:10,
        cursor: isMine?"default":"pointer",
        border:`1.5px solid ${isMine?"transparent":"#AA00FF44"}`,
        boxShadow: isMine?"none":"0 0 14px #AA00FF22"}}>
      {/* thumbnail blur (só quem enviou pode ver a prévia) */}
      <div style={{position:"relative", width:48, height:48, borderRadius:10, overflow:"hidden", flexShrink:0}}>
        <img src={msg.img} alt="" style={{width:"100%", height:"100%", objectFit:"cover",
          filter: isMine ? "none" : "blur(12px) brightness(.4)"}} />
        {!isMine && (
          <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",
            justifyContent:"center",fontSize:22}}>👁</div>
        )}
      </div>
      <div>
        <div style={{fontWeight:700, fontSize:"clamp(12px,3.5vw,14px)", color:"#fff", marginBottom:2}}>
          {isMine ? "Foto única enviada" : "Foto única"}
        </div>
        <div style={{fontSize:"clamp(10px,2.8vw,12px)",
          color: isMine?"#ffffff88":"#AA00FFcc", fontWeight:600}}>
          {isMine ? "🔥 Visível por 20s" : "👆 Toque para ver · 20s"}
        </div>
      </div>
    </div>
  );
}

// ═══ CHAT VIEW ════════════════════════════════════════════════
function ChatView({ user:u, msgs, onBack, onSend, title, subtitle="", nearby=false }) {
  const [txt,      setTxt]      = useState("");
  const [local,    setLocal]    = useState([...msgs]);
  const [mode,     setMode]     = useState("text"); // "text" | "once"
  const endRef  = useRef(null);
  const fileRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({behavior:"smooth"}); }, [local]);

  const send = () => {
    if (!txt.trim()) return;
    const m = { from:"me", text:txt, id:Date.now() };
    setLocal(p=>[...p,m]); onSend(m); setTxt("");
  };

  const sendFile = e => {
    const f = e.target.files[0];
    if (!f) return;
    const url = URL.createObjectURL(f);
    const m = mode === "once"
      ? { from:"me", img:url, id:Date.now(), once:true,  viewed:false } // foto única
      : { from:"me", img:url, id:Date.now(), once:false, viewed:false }; // foto normal
    setLocal(p=>[...p,m]);
    onSend(m);
    setMode("text"); // volta ao modo normal após enviar
    e.target.value = "";
  };

  const pickPhoto = (asOnce) => {
    setMode(asOnce ? "once" : "text");
    setTimeout(() => fileRef.current?.click(), 50);
  };

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100%",width:"100%",background:"#07070f"}}>
      <style>{GS}</style>

      {/* Header */}
      <div style={{display:"flex",alignItems:"center",gap:10,
        paddingTop:"max(env(safe-area-inset-top,0px),12px)",paddingBottom:12,
        paddingLeft:12,paddingRight:12,
        background:"#07070f",borderBottom:"1px solid #ffffff0a",flexShrink:0}}>
        <button onClick={onBack} style={{color:"#ffffffaa",fontSize:"clamp(17px,4.5vw,21px)",marginRight:2,lineHeight:1}}>←</button>
        <Av init={u.av} size="clamp(34px,9.5vw,42px)" img={u.p1||u.img} online={u.on} />
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,15px)",color:"#fff",
            overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{title}</div>
          {subtitle && <div style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#00B4FF"}}>{subtitle}</div>}
        </div>
        {/* indicador de modo foto única ativo */}
        {mode==="once" && (
          <div style={{background:"#FF005522",border:"1.5px solid #FF005544",borderRadius:8,
            padding:"4px 9px",display:"flex",alignItems:"center",gap:5}}>
            <span style={{fontSize:12}}>🔥</span>
            <span style={{fontSize:"clamp(9px,2.4vw,11px)",color:"#FF0055",fontWeight:700,fontFamily:"'Orbitron',monospace"}}>ÚNICA</span>
          </div>
        )}
      </div>

      {/* Messages */}
      <div style={{flex:1,overflowY:"auto",padding:"clamp(10px,3vw,14px)",
        display:"flex",flexDirection:"column",gap:"clamp(7px,2.5vw,10px)",
        WebkitOverflowScrolling:"touch"}}>
        {local.length===0 && (
          <div style={{textAlign:"center",color:"#ffffff44",fontSize:"clamp(12px,3.5vw,14px)",marginTop:44}}>
            Diga oi! 👋
          </div>
        )}
        {local.map(m=>(
          <div key={m.id} style={{display:"flex",justifyContent:m.from==="me"?"flex-end":"flex-start"}}>
            {/* foto única */}
            {m.once
              ? <OncePhoto msg={m} isMine={m.from==="me"} />
              /* foto normal */
              : m.img
                ? <div style={{maxWidth:"min(220px,65vw)",borderRadius:m.from==="me"?"18px 18px 5px 18px":"18px 18px 18px 5px",overflow:"hidden"}}>
                    <img src={m.img} alt="foto" style={{width:"100%",display:"block"}} />
                  </div>
                /* texto */
                : <div style={{maxWidth:"74%",borderRadius:m.from==="me"?"18px 18px 5px 18px":"18px 18px 18px 5px",
                    background:m.from==="me"?"linear-gradient(135deg,#AA00FF,#FF0055)":"#ffffff0f",
                    padding:"clamp(8px,2.5vw,11px) clamp(11px,3vw,14px)",
                    fontSize:"clamp(12px,3.5vw,14px)"}}>
                    {m.text}
                  </div>
            }
          </div>
        ))}
        <div ref={endRef} />
      </div>

      {/* Input bar */}
      <div style={{padding:"clamp(9px,2.5vw,12px) 12px",
        paddingBottom:"calc(clamp(10px,3vw,14px) + env(safe-area-inset-bottom,0px))",
        background:"#0c0c1a",borderTop:"1px solid #ffffff0a",
        display:"flex",gap:"clamp(6px,2vw,9px)",alignItems:"center",flexShrink:0}}>

        {/* hidden file input */}
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={sendFile} />

        {/* foto normal */}
        <button onClick={()=>pickPhoto(false)}
          style={{color:"#ffffff88",fontSize:"clamp(19px,5vw,23px)",lineHeight:1,flexShrink:0,
            padding:"2px",borderRadius:8,transition:"all .2s"}}>📷</button>

        {/* foto única 🔥 */}
        <button onClick={()=>pickPhoto(true)}
          title="Foto de visualização única (20s)"
          style={{color: mode==="once"?"#FF0055":"#ffffff55",
            fontSize:"clamp(19px,5vw,23px)",lineHeight:1,flexShrink:0,
            padding:"2px",borderRadius:8,transition:"all .2s",
            filter: mode==="once"?"drop-shadow(0 0 6px #FF0055)":"none"}}>🔥</button>

        {/* campo de texto */}
        <input value={txt} onChange={e=>setTxt(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&send()} placeholder="Mensagem…"
          style={{flex:1,background:"#ffffff0d",border:`1.5px solid ${mode==="once"?"#FF005544":"#ffffff18"}`,
            borderRadius:22,padding:"clamp(9px,2.5vw,12px) clamp(13px,3.5vw,16px)",
            color:"#fff",fontSize:"clamp(13px,3.5vw,15px)",transition:"border-color .2s"}} />

        {/* enviar */}
        <button onClick={send}
          style={{background:"linear-gradient(135deg,#AA00FF,#FF0055)",borderRadius:"50%",
            width:"clamp(36px,9vw,44px)",height:"clamp(36px,9vw,44px)",display:"flex",alignItems:"center",
            justifyContent:"center",fontSize:"clamp(15px,4vw,19px)",
            boxShadow:"0 0 14px #AA00FF55",flexShrink:0}}>↑</button>
      </div>
    </div>
  );
}

// ═══ BOTTOM NAV ═══════════════════════════════════════════════
function BotNav({ tab, setTab, onPost, tixCount }) {
  const LEFT  = [["feed","🏠","FEED"],["flirt","🔥","FLERTE"],["tickets","🎫","EVENTOS"]];
  const RIGHT = [["mytickets","🎟️","INGRESSOS"],["profile","👤","PERFIL"]];

  const activeColor = (id) => {
    if (id==="flirt") return "#FF0055";
    return "#AA00FF";
  };

  const Item = ({id,ic,lb,badge=0}) => (
    <button onClick={()=>setTab(id)}
      style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:"clamp(2px,1vw,4px)",
        position:"relative",padding:"4px 0",
        color: tab===id ? "#fff" : "#ffffffbb",
        filter: tab===id ? `drop-shadow(0 0 8px ${activeColor(id)}) brightness(1.25)` : "none",
        transition:"all .22s"}}>
      <span style={{fontSize:"clamp(19px,5.5vw,24px)",lineHeight:1}}>{ic}</span>
      <span style={{fontSize:"clamp(8px,2.2vw,10px)",fontFamily:"'Orbitron',monospace",letterSpacing:.5,
        fontWeight: tab===id?700:600,
        color: tab===id ? "#fff" : "#ffffffcc",
        textShadow: tab===id ? `0 0 10px ${activeColor(id)}99` : "none"}}>
        {lb}
      </span>
      {badge>0 && (
        <div style={{position:"absolute",top:0,right:"clamp(4px,2vw,10px)",background:"#FF0055",borderRadius:"50%",
          width:"clamp(14px,4vw,18px)",height:"clamp(14px,4vw,18px)",display:"flex",alignItems:"center",justifyContent:"center",
          fontSize:"clamp(8px,2.2vw,10px)",fontWeight:700,boxShadow:"0 0 8px #FF005577"}}>
          {badge}
        </div>
      )}
    </button>
  );

  return (
    <div style={{flexShrink:0,
      background:"linear-gradient(180deg,#0c0c1e 0%,#07070f 100%)",
      borderTop:"1.5px solid #ffffff18",
      boxShadow:"0 -6px 40px #00000099, inset 0 1px 0 #ffffff0f",
      display:"flex",alignItems:"center",
      paddingTop:"clamp(8px,2.5vw,11px)",
      paddingBottom:"calc(clamp(10px,3vw,14px) + env(safe-area-inset-bottom,0px))",
      position:"relative",   /* permite z-index */
      zIndex:90,             /* acima do conteúdo */
      width:"100%",
      overflow:"visible"}}> {/* permite botão + subir sem ser cortado */}
      {LEFT.map(([id,ic,lb])=><Item key={id} id={id} ic={ic} lb={lb} />)}
      {/* Center post button — sobe acima da barra */}
      <div style={{flex:"0 0 clamp(54px,15vw,66px)",display:"flex",justifyContent:"center",
        position:"relative",zIndex:91}}>
        <button onClick={onPost}
          style={{width:"clamp(50px,13.5vw,62px)",height:"clamp(50px,13.5vw,62px)",borderRadius:"50%",
            background:`linear-gradient(135deg,#AA00FF,#FF0055)`,
            border:"3px solid #07070f",display:"flex",alignItems:"center",justifyContent:"center",
            fontSize:"clamp(24px,7vw,30px)",lineHeight:1,color:"#fff",
            boxShadow:"0 0 28px #AA00FF99,0 4px 22px #FF005566",
            position:"absolute",                    /* sai do fluxo normal */
            bottom:"calc(100% - 22px)",             /* sobe acima da barra */
            left:"50%",transform:"translateX(-50%)",/* centraliza horizontalmente */
            zIndex:92,
            transition:"all .22s"}}>＋</button>
        {/* espaço vazio para manter o flex gap correto */}
        <div style={{width:"clamp(50px,13.5vw,62px)",height:"clamp(50px,13.5vw,62px)",opacity:0,pointerEvents:"none"}}/>
      </div>
      {RIGHT.map(([id,ic,lb])=><Item key={id} id={id} ic={ic} lb={lb} badge={id==="mytickets"?tixCount:0} />)}
    </div>
  );
}


// ═══ STORY MODAL ══════════════════════════════════════════════
function StoryMod({ user, onClose }) {
  const [prog,setProg]=useState(0);
  useEffect(()=>{
    const t=setInterval(()=>setProg(p=>{if(p>=100){clearInterval(t);onClose();return 100;}return p+1.4;}),50);
    return()=>clearInterval(t);
  },[]);

  const link = user.link || null;

  return (
    <div style={{position:"fixed",inset:0,background:"#000",zIndex:200,display:"flex",flexDirection:"column"}}>
      {/* Progress */}
      <div style={{height:3,background:"#ffffff1a",margin:"max(env(safe-area-inset-top,0px),40px) 12px 0"}}>
        <div style={{height:"100%",width:`${prog}%`,background:`linear-gradient(90deg,${RAINBOW.join(",")})`,transition:"width .05s linear"}} />
      </div>
      {/* Header */}
      <div style={{display:"flex",alignItems:"center",gap:9,padding:"11px 13px"}}>
        <Av init={user.av} size={36} img={user.img} />
        <span style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,15px)",color:"#fff",flex:1}}>{user.usr}</span>
        <button onClick={onClose} style={{color:"#ffffffaa",fontSize:22,lineHeight:1,padding:"2px 6px"}}>✕</button>
      </div>
      {/* Media — tap to close */}
      <div style={{flex:1,position:"relative",overflow:"hidden"}} onClick={onClose}>
        {user.img
          ? <img src={user.img} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={e=>e.target.style.display="none"} />
          : <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100%",fontSize:80}}>🌈</div>
        }
        {/* Caption */}
        {user.caption && (
          <div style={{position:"absolute",bottom:link?76:20,left:0,right:0,textAlign:"center",padding:"0 20px",pointerEvents:"none"}}>
            <div style={{display:"inline-block",background:"#000000cc",backdropFilter:"blur(8px)",
              borderRadius:12,padding:"8px 16px",fontSize:"clamp(13px,3.5vw,15px)",color:"#fff",lineHeight:1.5,maxWidth:"90%"}}>
              {user.caption}
            </div>
          </div>
        )}
      </div>
      {/* Link button — estilo Instagram */}
      {link && (
        <div style={{flexShrink:0,paddingBottom:"calc(16px + env(safe-area-inset-bottom,0px))",
          padding:"12px 20px calc(16px + env(safe-area-inset-bottom,0px))",
          background:"linear-gradient(transparent,#000000cc)",display:"flex",justifyContent:"center"}}>
          <a href={link} target="_blank" rel="noopener noreferrer"
            onClick={e=>e.stopPropagation()}
            style={{display:"flex",alignItems:"center",gap:9,background:"#ffffffee",borderRadius:30,
              padding:"clamp(11px,3vw,13px) clamp(20px,5.5vw,28px)",color:"#07070f",fontWeight:700,
              textDecoration:"none",fontSize:"clamp(13px,3.5vw,15px)",boxShadow:"0 4px 20px #00000055",
              maxWidth:300,overflow:"hidden"}}>
            <span style={{fontSize:18}}>🔗</span>
            <span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
              {link.replace(/^https?:\/\//,"").slice(0,30)}
            </span>
            <span style={{fontSize:16,flexShrink:0}}>›</span>
          </a>
        </div>
      )}
    </div>
  );
}


// ═══ TICKET / PAYMENT MODAL ═══════════════════════════════════
function TicketMod({ t, onClose, onBuy }) {
  const [step,setStep]=useState(0);
  const [pay,setPay]=useState("pix");
  const [proc,setProc]=useState(false);
  const [cn,setCn]=useState("");const [cname,setCname]=useState("");const [exp,setExp]=useState("");const [cvv,setCvv]=useState("");
  const commission = t.pn>0 ? +(t.pn*.15).toFixed(2) : 0;

  const doPay = async () => {
    setProc(true);
    try {
      await onBuy(t, pay, {cn,cname,exp,cvv});
      setStep(2);
    } catch(e) {
      alert("Erro no pagamento. Tente novamente.");
    } finally { setProc(false); }
  };

  return (
    <Sheet onClose={()=>!proc&&onClose()} title="">
      {/* STEP 0: Event details */}
      {step===0 && (
        <>
          <div style={{textAlign:"center",marginBottom:16}}>
            <div style={{fontSize:"clamp(36px,10vw,46px)",marginBottom:8}}>{t.ico||"🎫"}</div>
            <h3 style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(14px,4vw,17px)",marginBottom:3,color:"#fff"}}>{t.event}</h3>
            <p style={{color:"#ffffff77",fontSize:"clamp(11px,3vw,13px)"}}>📅 {t.date} · ⏰ {t.time} · 📍 {t.venue}</p>
          </div>
          {/* Price breakdown */}
          <div style={{background:"#ffffff07",borderRadius:12,padding:14,marginBottom:14}}>
            {[["Ingresso",t.price,"#ffffffcc"],
              ["Taxa plataforma (15%)",t.pn>0?`-R$${commission.toFixed(2)}`:"—","#FF6B00"],
              ["Total",t.price,"#FFD700"]].map(([k,v,c],i)=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderTop:i>0?"1px solid #ffffff0a":"none"}}>
                <span style={{color:"#ffffff88",fontSize:"clamp(11px,3vw,13px)"}}>{k}</span>
                <span style={{fontWeight:i===2?700:400,color:c,fontSize:i===2?"clamp(14px,4vw,16px)":"clamp(11px,3vw,13px)"}}>{v}</span>
              </div>
            ))}
          </div>
          {t.pn>0
            ? <Btn onClick={()=>setStep(1)} color="#FFD700" style={{width:"100%"}}>ESCOLHER PAGAMENTO 💳</Btn>
            : <Btn onClick={doPay} color="#00E676" style={{width:"100%",color:"#000"}}>GARANTIR GRATUITO ✓</Btn>
          }
        </>
      )}

      {/* STEP 1: Payment method */}
      {step===1 && (
        <>
          <p style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(11px,3vw,13px)",letterSpacing:1,marginBottom:14,color:"#fff"}}>💳 FORMA DE PAGAMENTO</p>
          <div style={{display:"flex",gap:5,marginBottom:16,flexWrap:"wrap"}}>
            {[["pix","PIX 🟢"],["credit","Crédito"],["debit","Débito"],["boleto","Boleto"]].map(([k,l])=>(
              <button key={k} onClick={()=>setPay(k)} style={{flex:1,minWidth:"clamp(55px,15vw,70px)",
                background:pay===k?"linear-gradient(135deg,#AA00FF,#FF0055)":"#ffffff0a",
                border:`1.5px solid ${pay===k?"#AA00FF55":"#ffffff15"}`,borderRadius:9,
                padding:"clamp(7px,2.5vw,9px) 4px",color:"#fff",fontSize:"clamp(10px,2.8vw,12px)",fontWeight:pay===k?700:400}}>
                {l}
              </button>
            ))}
          </div>

          {/* PIX */}
          {pay==="pix" && (
            <div style={{background:"#00E67609",border:"1.5px solid #00E67622",borderRadius:13,padding:"clamp(14px,4vw,20px)",textAlign:"center",marginBottom:14}}>
              <div style={{fontSize:"clamp(48px,13vw,66px)",marginBottom:10,filter:"drop-shadow(0 0 16px #00E67655)"}}>📱</div>
              <div style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(9px,2.5vw,12px)",color:"#00E676",marginBottom:8}}>PIX COPIA E COLA</div>
              <div style={{background:"#00E67610",border:"1.5px solid #00E67630",borderRadius:8,padding:"9px 13px",
                fontFamily:"monospace",fontSize:"clamp(9px,2.5vw,11px)",color:"#00E676",wordBreak:"break-all",marginBottom:9}}>
                00020126360014br.gov.bcb.pix0114CSQ-{Date.now().toString().slice(-8)}52040000530398654{t.pn.toFixed(2)}5802BR5911CENASQUARE6008BRASILIA62070503***6304XXXX
              </div>
              <button style={{background:"#00E67618",border:"1.5px solid #00E67633",borderRadius:7,padding:"7px 14px",color:"#00E676",fontSize:"clamp(11px,3vw,13px)"}}>📋 Copiar código PIX</button>
              <p style={{fontSize:"clamp(9px,2.5vw,11px)",color:"#ffffff44",marginTop:8}}>Válido por 30 minutos · Processado via Mercado Pago</p>
            </div>
          )}

          {/* Card */}
          {(pay==="credit"||pay==="debit") && (
            <div style={{display:"flex",flexDirection:"column",gap:9,marginBottom:14}}>
              <input value={cn} onChange={e=>setCn(e.target.value.replace(/\D/g,"").slice(0,16))} placeholder="Número do cartão" inputMode="numeric"
                style={{background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:11,padding:"clamp(11px,3vw,13px) 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,15px)",letterSpacing:2}} />
              <input value={cname} onChange={e=>setCname(e.target.value)} placeholder="Nome no cartão" autoCapitalize="characters"
                style={{background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:11,padding:"clamp(11px,3vw,13px) 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,15px)"}} />
              <div style={{display:"flex",gap:9}}>
                <input value={exp} onChange={e=>setExp(e.target.value)} placeholder="MM/AA" inputMode="numeric"
                  style={{flex:1,background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:11,padding:"clamp(11px,3vw,13px) 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,15px)"}} />
                <input value={cvv} onChange={e=>setCvv(e.target.value.slice(0,4))} placeholder="CVV" inputMode="numeric" type="password"
                  style={{flex:1,background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:11,padding:"clamp(11px,3vw,13px) 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,15px)"}} />
              </div>
              {pay==="credit" && (
                <div style={{background:"#AA00FF09",border:"1.5px solid #AA00FF1a",borderRadius:10,padding:"11px 13px"}}>
                  <p style={{fontSize:"clamp(10px,3vw,12px)",color:"#ffffffaa",marginBottom:7,fontWeight:600}}>Parcelamento sem juros:</p>
                  {[`1x ${t.price}`,`2x R$${(t.pn/2).toFixed(2).replace(".",",")}`,`3x R$${(t.pn/3).toFixed(2).replace(".",",")}`].map(o=>(
                    <label key={o} style={{display:"flex",alignItems:"center",gap:8,fontSize:"clamp(11px,3vw,13px)",color:"#ffffffcc",padding:"4px 0",cursor:"pointer"}}>
                      <input type="radio" name="parc" style={{accentColor:"#AA00FF"}} /> {o}
                    </label>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Boleto */}
          {pay==="boleto" && (
            <div style={{background:"#ffffff07",border:"1.5px solid #ffffff0f",borderRadius:13,padding:"clamp(14px,4vw,18px)",textAlign:"center",marginBottom:14}}>
              <div style={{fontSize:"clamp(38px,11vw,52px)",marginBottom:9}}>🧾</div>
              <p style={{fontSize:"clamp(13px,3.5vw,15px)",color:"#ffffffcc",marginBottom:5}}>Boleto bancário</p>
              <p style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffff55"}}>Vence em 3 dias úteis · Processado via Mercado Pago</p>
            </div>
          )}

          <Btn onClick={doPay} color="#AA00FF" style={{width:"100%"}} disabled={proc}>
            {proc?"⏳ Processando...":"PAGAR "+t.price+" 🔒"}
          </Btn>
          <button onClick={()=>setStep(0)} style={{width:"100%",color:"#ffffff66",fontSize:"clamp(11px,3vw,13px)",marginTop:10,padding:6}}>← voltar</button>
        </>
      )}

      {/* STEP 2: Success */}
      {step===2 && (
        <div style={{textAlign:"center",padding:"16px 0"}}>
          <div style={{fontSize:"clamp(44px,12vw,58px)",marginBottom:12,filter:"drop-shadow(0 0 20px #00E67677)"}}>✅</div>
          <h3 style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(14px,4vw,17px)",marginBottom:7,color:"#00E676"}}>Ingresso Garantido!</h3>
          <p style={{color:"#ffffff77",fontSize:"clamp(11px,3vw,13px)",marginBottom:4}}>{t.event}</p>
          <p style={{color:"#ffffff55",fontSize:"clamp(10px,2.8vw,12px)",marginBottom:16}}>📧 Confirmação enviada por email</p>
          <div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:14,flexWrap:"wrap"}}>
            <div style={{padding:"7px 14px",background:"#00E67611",border:"1.5px solid #00E67633",borderRadius:8,fontSize:"clamp(10px,2.8vw,12px)",color:"#00E676"}}>🎟️ Em Meus Ingressos</div>
            <div style={{padding:"7px 14px",background:"#00B4FF11",border:"1.5px solid #00B4FF33",borderRadius:8,fontSize:"clamp(10px,2.8vw,12px)",color:"#00B4FF"}}>📧 Email enviado</div>
          </div>
          <button onClick={onClose} style={{background:"#ffffff0a",border:"1.5px solid #ffffff15",borderRadius:11,padding:"11px 26px",color:"#ffffffcc",fontSize:"clamp(12px,3.5vw,14px)"}}>Fechar</button>
        </div>
      )}
    </Sheet>
  );
}

// ═══ NEW POST MODAL ════════════════════════════════════════════
function NewPostMod({ onClose, onPost, me }) {
  const [cap,    setCap]    = useState("");
  const [isT,    setIsT]    = useState(false);
  const [isEv,   setIsEv]   = useState(false);
  const [imgs,   setImgs]   = useState([]);     // array de URLs (carrossel)
  const [selIdx, setSelIdx] = useState(0);      // imagem selecionada no preview
  const fileRef = useRef(null);

  const pick = e => {
    const files = Array.from(e.target.files);
    if (!files.length) return;
    const newUrls = files.map(f => URL.createObjectURL(f));
    setImgs(prev => {
      const merged = [...prev, ...newUrls].slice(0, 10); // máx 10
      setSelIdx(merged.length - 1);
      return merged;
    });
    e.target.value = ""; // permite selecionar os mesmos arquivos novamente
  };

  const removeImg = idx => {
    setImgs(prev => {
      const next = prev.filter((_,i)=>i!==idx);
      setSelIdx(Math.min(selIdx, next.length-1));
      return next;
    });
  };

  const post = () => {
    onPost({
      id:       Date.now(),
      uid:      me?.username || "você",
      usr:      me?.username || "você",
      av:       me?.av  || "EU",
      ai:       me?.img || null,
      img:      imgs[0] || UP.party[Math.floor(Math.random()*UP.party.length)],
      imgs:     imgs.length > 0 ? imgs : null,   // carrossel
      lk:0, cm:0, comments:[],
      cap:      cap || "🌈",
      T:isT, W:isT,
      ev: isEv && (me?.role === "admin"),
      tk:null, tm:"agora", fl:false, bl:false, ok:true
    });
    onClose();
  };

  return (
    <Sheet onClose={onClose} title="NOVA PUBLICAÇÃO">
      {me?.role==="admin" && (
        <div style={{padding:"6px 12px 8px",background:"#AA00FF0d",border:"1.5px solid #AA00FF1a",borderRadius:9,marginBottom:12,display:"flex",gap:7,alignItems:"center"}}>
          <span style={{fontSize:14}}>⚡</span>
          <span style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#AA00FFCC"}}>Administradores podem publicar eventos e ingressos.</span>
        </div>
      )}

      {/* Hidden file input — multiple */}
      <input ref={fileRef} type="file" accept="image/*,video/*" multiple style={{display:"none"}} onChange={pick} />

      {/* Preview + thumbnails */}
      {imgs.length === 0 ? (
        <div onClick={()=>fileRef.current?.click()}
          style={{background:"#ffffff07",borderRadius:13,height:150,marginBottom:12,
            border:"2px dashed #ffffff18",cursor:"pointer",overflow:"hidden",
            display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:8}}>
          <span style={{fontSize:"clamp(26px,7vw,34px)"}}>📸</span>
          <span style={{color:"#ffffff55",fontSize:"clamp(12px,3.5vw,14px)"}}>Selecionar fotos / vídeo</span>
          <span style={{color:"#ffffff33",fontSize:"clamp(9px,2.5vw,11px)"}}>Até 10 imagens · carrossel automático</span>
        </div>
      ) : (
        <div style={{marginBottom:12}}>
          {/* Imagem principal selecionada */}
          <div style={{borderRadius:13,overflow:"hidden",aspectRatio:"1",marginBottom:8,position:"relative"}}>
            <img src={imgs[selIdx]} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}} />
            {imgs.length > 1 && (
              <div style={{position:"absolute",top:8,right:8,background:"#000000bb",backdropFilter:"blur(8px)",
                borderRadius:20,padding:"4px 10px",fontFamily:"'Orbitron',monospace",
                fontSize:"clamp(10px,2.8vw,12px)",color:"#fff",fontWeight:700}}>
                {selIdx+1}/{imgs.length}
              </div>
            )}
          </div>
          {/* Linha de thumbnails */}
          <div style={{display:"flex",gap:6,overflowX:"auto",scrollbarWidth:"none",paddingBottom:2}}>
            {imgs.map((src,i)=>(
              <div key={i} style={{position:"relative",flexShrink:0,
                width:"clamp(52px,14vw,64px)",height:"clamp(52px,14vw,64px)",borderRadius:9,overflow:"hidden",
                border:`2px solid ${i===selIdx?"#AA00FF":"#ffffff18"}`,cursor:"pointer"}}
                onClick={()=>setSelIdx(i)}>
                <img src={src} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} />
                <button onClick={e=>{e.stopPropagation();removeImg(i);}}
                  style={{position:"absolute",top:2,right:2,background:"#000000cc",borderRadius:"50%",
                    width:18,height:18,display:"flex",alignItems:"center",justifyContent:"center",
                    color:"#fff",fontSize:11,lineHeight:1}}>✕</button>
              </div>
            ))}
            {/* Botão adicionar mais */}
            {imgs.length < 10 && (
              <div onClick={()=>fileRef.current?.click()}
                style={{flexShrink:0,width:"clamp(52px,14vw,64px)",height:"clamp(52px,14vw,64px)",
                  borderRadius:9,border:"2px dashed #ffffff22",cursor:"pointer",
                  display:"flex",alignItems:"center",justifyContent:"center",
                  color:"#ffffff55",fontSize:"clamp(18px,5vw,22px)"}}>+</div>
            )}
          </div>
        </div>
      )}

      <textarea value={cap} onChange={e=>setCap(e.target.value)} placeholder="Escreva uma legenda…"
        style={{width:"100%",background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:11,
          padding:11,color:"#fff",fontSize:"clamp(12px,3.5vw,14px)",minHeight:60,resize:"none",marginBottom:12}} />

      <div style={{display:"flex",gap:16,marginBottom:14}}>
        {[["isT","🔞 T18+","#FF0055",isT,setIsT],...(me?.role==="admin"?[["isEv","🎫 Evento","#FFD700",isEv,setIsEv]]:[])]
          .map(([k,lb,c,val,setter])=>(
          <label key={k} style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}}>
            <input type="checkbox" checked={val} onChange={e=>setter(e.target.checked)} style={{accentColor:c,width:17,height:17}} />
            <span style={{fontSize:"clamp(12px,3.5vw,14px)",color:val?c:"#ffffffaa",fontWeight:val?700:400}}>{lb}</span>
          </label>
        ))}
      </div>

      <Btn onClick={post} color="#AA00FF" style={{width:"100%"}} disabled={imgs.length===0}>
        {imgs.length===0 ? "Selecione uma foto primeiro" : `PUBLICAR${imgs.length>1?" ("+imgs.length+" fotos)":""} 🚀`}
      </Btn>
    </Sheet>
  );
}

