            <div style={{fontSize:"clamp(11px,3.2vw,14px)",color:"#ffffffaa"}}>{u.age} anos · {u.on?<span style={{color:"#00E676"}}>🟢 Online</span>:<span style={{color:"#ffffff44"}}>⚫ Offline</span>}</div>
