// ═══ USER PROFILE MODAL (perfil de outro usuário) ════════════
function UserProfileMod({ user, posts, isFollowing, onFollow, onClose, onChat, onTicket }) {
  const [pt,setPt]=useState("posts");
  const filtered = pt==="posts"?posts:posts.filter(p=>p.ev);
  const u = user;
  const dispName = u.displayName||u.username||u.sn||u.uid||"Usuário";
  const avatar = u.av||u.avatar||"?";
  const imgSrc = u.img||u.avatarImg||u.p1||null;
  const bio = u.bio||"";
  const postCount = posts.length;

  return (
    <div style={{position:"fixed",inset:0,background:"#07070f",zIndex:200,display:"flex",flexDirection:"column",overflowY:"auto",WebkitOverflowScrolling:"touch"}}>
      <style>{`body{overflow:hidden}`}</style>
      {/* Header */}
      <div style={{display:"flex",alignItems:"center",gap:11,padding:"max(env(safe-area-inset-top,0px),14px) 14px 13px",background:"#07070f",borderBottom:"1px solid #ffffff0a",flexShrink:0,position:"sticky",top:0,zIndex:10}}>
        <button onClick={onClose} style={{color:"#ffffffaa",fontSize:22,lineHeight:1,padding:"2px 4px"}}>←</button>
        <span style={{fontWeight:700,fontSize:"clamp(14px,4vw,17px)",color:"#fff",flex:1}}>@{dispName}</span>
        <button onClick={onChat} style={{background:"linear-gradient(135deg,#AA00FF,#FF0055)",borderRadius:10,padding:"7px 13px",color:"#fff",fontSize:"clamp(11px,3vw,13px)",fontWeight:700,fontFamily:"'Orbitron',monospace"}}>✉ Chat</button>
      </div>
      {/* Profile info */}
      <div style={{padding:"16px 14px 12px"}}>
        <div style={{display:"flex",gap:14,alignItems:"center",marginBottom:13}}>
          <Av init={avatar} size="clamp(64px,18vw,80px)" img={imgSrc} rainbow />
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontWeight:700,fontSize:"clamp(14px,4vw,17px)",color:"#fff",marginBottom:3}}>{dispName}</div>
            {bio&&<div style={{fontSize:"clamp(11px,3vw,13px)",color:"#ffffffaa",marginBottom:8,lineHeight:1.5}}>{bio}</div>}
            <div style={{display:"flex",gap:"clamp(10px,3vw,18px)"}}>
              {[[postCount,"posts"],[Math.floor(Math.random()*500+50),"seguidores"],[Math.floor(Math.random()*200+10),"seguindo"]].map(([n,l])=>(
                <div key={l} style={{textAlign:"center"}}>
                  <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,16px)",color:"#fff"}}>{n}</div>
                  <div style={{fontSize:"clamp(9px,2.5vw,11px)",color:"#ffffff77"}}>{l}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
        {/* Follow button */}
        <button onClick={onFollow}
          style={{width:"100%",background:isFollowing?"#ffffff0d":"linear-gradient(135deg,#AA00FF,#FF0055)",
            border:`1.5px solid ${isFollowing?"#ffffff22":"transparent"}`,borderRadius:12,
            padding:"clamp(10px,3vw,13px)",color:"#fff",fontSize:"clamp(12px,3.5vw,14px)",
            fontWeight:700,fontFamily:"'Orbitron',monospace",
            boxShadow:isFollowing?"none":"0 4px 20px #AA00FF44",marginBottom:4}}>
          {isFollowing?"✓ Seguindo":"+ Seguir"}
        </button>
      </div>
      {/* Tabs */}
      <div style={{display:"flex",borderBottom:"1.5px solid #ffffff0d",flexShrink:0}}>
        {["posts","eventos"].map(t=>(
          <button key={t} onClick={()=>setPt(t)} style={{flex:1,background:"none",color:pt===t?"#fff":"#ffffff55",
            padding:"clamp(8px,2.5vw,11px) 0",fontSize:"clamp(9px,2.5vw,11px)",fontFamily:"'Orbitron',monospace",letterSpacing:1,
            borderBottom:pt===t?"2.5px solid #AA00FF":"2.5px solid transparent",transition:"all .2s"}}>
            {t.toUpperCase()}
          </button>
        ))}
      </div>
      {/* Posts grid */}
      {filtered.length===0
        ? <div style={{textAlign:"center",padding:"clamp(32px,8vw,52px) 20px",color:"#ffffff44",fontSize:"clamp(12px,3.5vw,14px)"}}>
            Nenhuma publicação ainda.
          </div>
        : <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:1.5,marginTop:1.5}}>
            {filtered.map(p=>(
              <div key={p.id} onClick={()=>p.tk&&onTicket(p.tk)} style={{aspectRatio:"1",overflow:"hidden",position:"relative",cursor:p.tk?"pointer":"default"}}>
                <img src={p.img} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={e=>e.target.style.display="none"} />
                {p.ev&&<div style={{position:"absolute",top:4,right:4,fontSize:13}}>🎫</div>}
                {p.T&&<div style={{position:"absolute",top:4,left:4,fontSize:9,background:"#FF005599",borderRadius:4,padding:"2px 5px",fontFamily:"'Orbitron',monospace",color:"#fff",fontWeight:700}}>T</div>}
              </div>
            ))}
          </div>
      }
    </div>
  );
}

// ═══ EDIT PROFILE MODAL ══════════════════════════════════════
function EditProfileMod({ me, myProfile, onClose, onSave }) {
  const [dn,  setDn]  = useState(myProfile.displayName||me.username||"");
  const [bio, setBio] = useState(myProfile.bio||me.bio||"");
  const [web, setWeb] = useState(myProfile.website||"");
  const [img, setImg] = useState(me.img||null);
  const fileRef = useRef(null);

  const pickImg = e => {
    const f = e.target.files[0];
    if (f) setImg(URL.createObjectURL(f));
  };

  return (
    <Sheet onClose={onClose} title="✏️ EDITAR PERFIL">
      {/* Avatar picker */}
      <div style={{display:"flex",justifyContent:"center",marginBottom:18}}>
        <div onClick={()=>fileRef.current?.click()} style={{position:"relative",cursor:"pointer"}}>
          <Av init={me.av} size={80} img={img} rainbow />
          <div style={{position:"absolute",bottom:0,right:0,background:"#AA00FF",borderRadius:"50%",width:26,height:26,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,border:"2px solid #07070f"}}>📷</div>
        </div>
        <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={pickImg} />
      </div>
      {/* Fields */}
      <div style={{display:"flex",flexDirection:"column",gap:11,marginBottom:18}}>
        {[["Nome de exibição",dn,setDn,"text"],["Bio",bio,setBio,"text"],["Site / Link",web,setWeb,"url"]].map(([pl,val,setter,tp])=>(
          <div key={pl}>
            <p style={{fontSize:"clamp(9px,2.4vw,11px)",color:"#ffffff88",marginBottom:5,fontFamily:"'Orbitron',monospace",letterSpacing:.5}}>{pl.toUpperCase()}</p>
            {pl==="Bio"
              ? <textarea value={val} onChange={e=>setter(e.target.value)} placeholder={pl} rows={3}
                  style={{width:"100%",background:"#ffffff0d",border:"1.5px solid #ffffff1a",borderRadius:12,padding:"11px 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,15px)",resize:"none"}} />
              : <input value={val} onChange={e=>setter(e.target.value)} placeholder={pl} type={tp}
                  style={{width:"100%",background:"#ffffff0d",border:"1.5px solid #ffffff1a",borderRadius:12,padding:"11px 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,15px)"}} />
            }
          </div>
        ))}
      </div>
      <Btn onClick={()=>onSave({displayName:dn,bio,website:web,avatarUrl:img})} color="#AA00FF" style={{width:"100%"}}>SALVAR ALTERAÇÕES ✓</Btn>
    </Sheet>
  );
}

// ═══ FOLLOWERS / FOLLOWING MODAL ═════════════════════════════
function FollowersMod({ type, ids, allUsers, nearby, onClose, onView }) {
  // Monta lista com dados dos usuários conhecidos
  const list = ids.length > 0 ? ids.map(uid => {
    const u = allUsers[uid] || nearby.find(n=>n.uid===uid);
    return u ? { uid, name: u.username||u.sn||uid, img: u.img||u.p1||null, av: u.av||uid.slice(0,2).toUpperCase() } : { uid, name: uid, img:null, av:uid.slice(0,2).toUpperCase() };
  }) : [];

  // Demo: se lista vazia, mostra exemplos da comunidade
  const demoList = Object.entries(allUsers).slice(0,3).map(([k,u])=>({ uid:k, name:u.username||k, img:u.img, av:u.av }));
  const display = list.length > 0 ? list : demoList;

  return (
    <Sheet onClose={onClose} title={type==="followers"?"👥 SEGUIDORES":"👣 SEGUINDO"}>
      {display.length===0
        ? <div style={{textAlign:"center",padding:"28px 0",color:"#ffffff55",fontSize:"clamp(12px,3.5vw,14px)"}}>
            {type==="followers"?"Nenhum seguidor ainda.":"Você não segue ninguém ainda."}
          </div>
        : display.map(u=>(
          <div key={u.uid} onClick={()=>onView({uid:u.uid,...(allUsers[u.uid]||{})})}
            style={{display:"flex",alignItems:"center",gap:11,padding:"11px 0",borderBottom:"1px solid #ffffff08",cursor:"pointer"}}>
            <Av init={u.av} size={44} img={u.img} />
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,15px)",color:"#fff"}}>{u.name}</div>
              <div style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffff55"}}>@{u.uid}</div>
            </div>
            <span style={{color:"#AA00FF",fontSize:16}}>›</span>
          </div>
        ))
      }
    </Sheet>
  );
}

// ═══ SEARCH MODAL ════════════════════════════════════════════
function SearchMod({ posts, allUsers, nearby, isFollowing, onFollow, onClose, onView }) {
  const [q,setQ]=useState("");

  // Combina USERS + INIT_NEARBY numa lista unificada
  const allPeople = [
    ...Object.entries(allUsers).map(([uid,u])=>({ uid, name:u.username||uid, img:u.img||null, av:u.av||"?", bio:u.bio||"", posts: posts.filter(p=>p.uid===uid).length })),
    ...nearby.filter(u=>!allUsers[u.uid]).map(u=>({ uid:u.uid, name:u.sn||u.uid, img:u.p1||null, av:u.av||"?", bio:u.bio||"", posts:0 })),
  ];

  const results = q.trim()===""
    ? allPeople
    : allPeople.filter(u =>
        u.name.toLowerCase().includes(q.toLowerCase()) ||
        u.uid.toLowerCase().includes(q.toLowerCase()) ||
        u.bio.toLowerCase().includes(q.toLowerCase())
      );

  return (
    <div style={{position:"fixed",inset:0,background:"#07070f",zIndex:200,display:"flex",flexDirection:"column"}}>
      <style>{`body{overflow:hidden}`}</style>
      {/* Search header */}
      <div style={{padding:"max(env(safe-area-inset-top,0px),14px) 14px 12px",background:"#07070f",borderBottom:"1px solid #ffffff0a",flexShrink:0}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
          <button onClick={onClose} style={{color:"#ffffffaa",fontSize:22,lineHeight:1}}>←</button>
          <h2 style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(12px,3.5vw,15px)",color:"#fff",letterSpacing:1,flex:1}}>🔍 BUSCAR PESSOAS</h2>
        </div>
        <div style={{position:"relative"}}>
          <span style={{position:"absolute",left:13,top:"50%",transform:"translateY(-50%)",fontSize:15,pointerEvents:"none"}}>🔍</span>
          <input autoFocus value={q} onChange={e=>setQ(e.target.value)} placeholder="Nome, usuário, bio…"
            style={{width:"100%",background:"#ffffff0d",border:"1.5px solid #AA00FF44",borderRadius:14,
              padding:"clamp(11px,3vw,13px) 14px clamp(11px,3vw,13px) 38px",
              color:"#fff",fontSize:"clamp(13px,3.5vw,15px)"}} />
          {q&&<button onClick={()=>setQ("")} style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",color:"#ffffff55",fontSize:16}}>✕</button>}
        </div>
      </div>
      {/* Results */}
      <div style={{flex:1,overflowY:"auto",WebkitOverflowScrolling:"touch"}}>
        {q===""&&<p style={{padding:"12px 16px",fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffff44",fontFamily:"'Orbitron',monospace",letterSpacing:1}}>COMUNIDADE · BRASÍLIA</p>}
        {results.length===0
          ? <div style={{textAlign:"center",padding:"44px 20px",color:"#ffffff44",fontSize:"clamp(13px,3.5vw,15px)"}}>
              Nenhum resultado para "{q}"
            </div>
          : results.map(u=>(
            <div key={u.uid} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 16px",borderBottom:"1px solid #ffffff08"}}>
              <div onClick={()=>onView({uid:u.uid,...(allUsers[u.uid]||{})})} style={{cursor:"pointer",flexShrink:0}}>
                <Av init={u.av} size={48} img={u.img} />
              </div>
              <div style={{flex:1,minWidth:0,cursor:"pointer"}} onClick={()=>onView({uid:u.uid,...(allUsers[u.uid]||{})})}>
                <div style={{fontWeight:700,fontSize:"clamp(13px,3.5vw,15px)",color:"#fff"}}>{u.name}</div>
                <div style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffff55",marginBottom:u.bio?2:0}}>@{u.uid} · {u.posts} posts</div>
                {u.bio&&<div style={{fontSize:"clamp(10px,2.8vw,12px)",color:"#ffffffaa",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{u.bio}</div>}
              </div>
              <button onClick={()=>onFollow(u.uid)}
                style={{flexShrink:0,background:isFollowing(u.uid)?"#ffffff0d":"linear-gradient(135deg,#AA00FF,#FF0055)",
                  border:`1.5px solid ${isFollowing(u.uid)?"#ffffff22":"transparent"}`,borderRadius:10,
                  padding:"7px 13px",color:"#fff",fontSize:"clamp(10px,2.8vw,12px)",fontWeight:700}}>
                {isFollowing(u.uid)?"✓":"+ Seguir"}
              </button>
            </div>
          ))
        }
      </div>
    </div>
  );
}

// ═══ NEW STORY MODAL ══════════════════════════════════════════
function NewStoryMod({ onClose, onPost, me }) {
  const [prev,     setPrev]     = useState(null);
  const [mediaType,setMediaType]= useState("image");
  const [caption,  setCaption]  = useState("");
  const [link,     setLink]     = useState("");      // link estilo Instagram
  const [showLink, setShowLink] = useState(false);  // toggle campo link
  const fileRef  = useRef(null);
  const videoRef = useRef(null);

  const pick = e => {
    const f = e.target.files[0];
    if (!f) return;
    setMediaType(f.type.startsWith("video/") ? "video" : "image");
    setPrev(URL.createObjectURL(f));
  };

  const fmtLink = raw => {
    if (!raw) return "";
    if (/^https?:\/\//i.test(raw)) return raw;
    return "https://" + raw;
  };

  const post = () => {
    if (!prev) return;
    onPost({ img:prev, mediaType, caption, link: fmtLink(link) });
    onClose();
  };

  return (
    <div style={{position:"fixed",inset:0,background:"#07070f",zIndex:250,display:"flex",flexDirection:"column"}}>
      <style>{GS}</style>

      {/* Header */}
      <div style={{display:"flex",alignItems:"center",gap:11,
        paddingTop:"max(env(safe-area-inset-top,0px),14px)",paddingBottom:12,
        paddingLeft:12,paddingRight:12,
        background:"#07070f",borderBottom:"1px solid #ffffff0a",flexShrink:0}}>
        <button onClick={onClose} style={{color:"#ffffffaa",fontSize:22,lineHeight:1,padding:"2px 4px"}}>✕</button>
        <h2 style={{flex:1,fontFamily:"'Orbitron',monospace",fontSize:"clamp(12px,3.5vw,15px)",
          letterSpacing:1,color:"#fff",textAlign:"center"}}>NOVO STORY</h2>
        <button onClick={post} disabled={!prev}
          style={{background:prev?"linear-gradient(135deg,#AA00FF,#FF0055)":"#ffffff15",
            border:"none",borderRadius:12,padding:"8px 16px",color:prev?"#fff":"#ffffff44",
            fontSize:"clamp(12px,3.5vw,14px)",fontWeight:700,fontFamily:"'Orbitron',monospace",
            boxShadow:prev?"0 0 14px #AA00FF44":"none"}}>
          PUBLICAR
        </button>
      </div>

      {/* Preview */}
      <div style={{flex:1,position:"relative",background:"#000",display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}>
        {!prev ? (
          <div onClick={()=>fileRef.current?.click()}
            style={{display:"flex",flexDirection:"column",alignItems:"center",gap:16,cursor:"pointer",padding:32}}>
            <div style={{width:90,height:90,borderRadius:"50%",
              background:`conic-gradient(${RAINBOW.join(",")})`,padding:3,
              display:"flex",alignItems:"center",justifyContent:"center"}}>
              <div style={{width:"100%",height:"100%",borderRadius:"50%",background:"#07070f",
                display:"flex",alignItems:"center",justifyContent:"center",fontSize:32}}>📷</div>
            </div>
            <div style={{textAlign:"center"}}>
              <p style={{color:"#fff",fontWeight:700,fontSize:"clamp(14px,4vw,17px)",marginBottom:6}}>Adicionar ao story</p>
              <p style={{color:"#ffffff66",fontSize:"clamp(11px,3vw,13px)",lineHeight:1.5}}>
                Fotos e vídeos curtos<br/>até <strong style={{color:"#AA00FF"}}>10 segundos</strong> · visíveis por 24h
              </p>
            </div>
            <div style={{display:"flex",gap:12}}>
              {[["🖼️","Foto"],["🎬","Vídeo 10s"],["🔗","Link"]].map(([ic,lb])=>(
                <div key={lb} style={{background:"#ffffff0d",borderRadius:12,padding:"10px 14px",
                  display:"flex",alignItems:"center",gap:7,border:"1.5px solid #ffffff15"}}>
                  <span style={{fontSize:16}}>{ic}</span>
                  <span style={{color:"#fff",fontSize:"clamp(11px,3vw,13px)",fontWeight:600}}>{lb}</span>
                </div>
              ))}
            </div>
          </div>
        ) : mediaType==="video" ? (
          <video ref={videoRef} src={prev} style={{maxWidth:"100%",maxHeight:"100%",objectFit:"contain"}}
            controls autoPlay muted loop />
        ) : (
          <img src={prev} alt="" style={{maxWidth:"100%",maxHeight:"100%",objectFit:"contain"}} />
        )}

        {/* Overlay botões quando tem mídia */}
        {prev && (
          <>
            <button onClick={()=>fileRef.current?.click()}
              style={{position:"absolute",top:14,left:14,background:"#000000bb",backdropFilter:"blur(8px)",
                borderRadius:10,padding:"7px 12px",color:"#fff",fontSize:"clamp(11px,3vw,13px)",
                border:"1.5px solid #ffffff22",display:"flex",alignItems:"center",gap:6}}>
              📷 Trocar
            </button>
            {/* Botão Link no preview */}
            <button onClick={()=>setShowLink(v=>!v)}
              style={{position:"absolute",top:14,right:14,background:link?"linear-gradient(135deg,#AA00FF,#FF0055)":"#000000bb",
                backdropFilter:"blur(8px)",borderRadius:10,padding:"7px 12px",
                color:"#fff",fontSize:"clamp(11px,3vw,13px)",
                border:`1.5px solid ${link?"#AA00FF55":"#ffffff22"}`,
                display:"flex",alignItems:"center",gap:6,
                boxShadow:link?"0 0 12px #AA00FF55":"none"}}>
              🔗 {link ? "Link ✓" : "Adicionar link"}
            </button>
          </>
        )}

        {/* Preview do link sobre a imagem */}
        {prev && link && !showLink && (
          <div style={{position:"absolute",bottom:14,left:"50%",transform:"translateX(-50%)",
            background:"#000000cc",backdropFilter:"blur(10px)",borderRadius:20,
            padding:"8px 18px",display:"flex",alignItems:"center",gap:7,
            border:"1.5px solid #AA00FF44",maxWidth:"80%"}}>
            <span style={{fontSize:14}}>🔗</span>
            <span style={{color:"#AA00FF",fontSize:"clamp(10px,2.8vw,12px)",
              overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontWeight:600}}>
              {link.replace(/^https?:\/\//,"").slice(0,32)}
            </span>
            <span style={{color:"#ffffff55",fontSize:"clamp(9px,2.4vw,11px)"}}>Ver mais ›</span>
          </div>
        )}

        {/* Input de link expandido */}
        {prev && showLink && (
          <div onClick={e=>e.stopPropagation()}
            style={{position:"absolute",bottom:0,left:0,right:0,
              background:"#0e0e1e",borderTop:"1.5px solid #AA00FF33",
              padding:"clamp(14px,4vw,18px)",
              backdropFilter:"blur(20px)"}}>
            <p style={{fontFamily:"'Orbitron',monospace",fontSize:"clamp(9px,2.5vw,11px)",
              color:"#AA00FF",letterSpacing:.5,marginBottom:9}}>🔗 LINK DO STORY</p>
            <div style={{display:"flex",gap:8}}>
              <input value={link} onChange={e=>setLink(e.target.value)}
                placeholder="exemplo.com.br ou URL completa"
                autoCapitalize="none" autoCorrect="off" inputMode="url"
                style={{flex:1,background:"#ffffff0d",border:`1.5px solid ${link?"#AA00FF55":"#ffffff18"}`,
                  borderRadius:12,padding:"clamp(10px,3vw,13px) 12px",
                  color:"#fff",fontSize:"clamp(13px,3.5vw,15px)"}} />
              <button onClick={()=>setShowLink(false)}
                style={{background:"linear-gradient(135deg,#AA00FF,#FF0055)",border:"none",borderRadius:12,
                  padding:"0 16px",color:"#fff",fontWeight:700,fontSize:"clamp(12px,3.5vw,14px)"}}>OK</button>
            </div>
            {link && (
              <button onClick={()=>{ setLink(""); setShowLink(false); }}
                style={{marginTop:8,color:"#FF005588",fontSize:"clamp(10px,2.8vw,12px)"}}>
                ✕ Remover link
              </button>
            )}
            <p style={{marginTop:8,fontSize:"clamp(9px,2.5vw,10px)",color:"#ffffff33"}}>
              O link aparecerá como botão "Ver mais" no seu story
            </p>
          </div>
        )}

        {prev && mediaType==="video" && (
          <div style={{position:"absolute",bottom:showLink?120:14,left:"50%",transform:"translateX(-50%)",
            background:"#000000cc",backdropFilter:"blur(8px)",borderRadius:20,padding:"6px 14px",
            fontSize:"clamp(10px,2.8vw,12px)",color:"#FFD700",display:"flex",alignItems:"center",gap:6,
            border:"1.5px solid #FFD70033"}}>
            ⏱️ Apenas os primeiros 10s serão exibidos
          </div>
        )}
      </div>

      {/* Bottom: caption + file input */}
      <div style={{flexShrink:0,background:"#0c0c1a",borderTop:"1px solid #ffffff0a",
        padding:"clamp(10px,3vw,14px) 12px",
        paddingBottom:"calc(clamp(10px,3vw,14px) + env(safe-area-inset-bottom,0px))"}}>
        {prev && (
          <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:11}}>
            <Av init={me?.av||"EU"} size={34} img={me?.img} />
            <input value={caption} onChange={e=>setCaption(e.target.value)}
              placeholder="Legenda do story… (opcional)"
              style={{flex:1,background:"#ffffff0d",border:"1.5px solid #ffffff18",borderRadius:20,
                padding:"clamp(9px,2.5vw,11px) 14px",color:"#fff",fontSize:"clamp(13px,3.5vw,14px)"}} />
          </div>
        )}
        <input ref={fileRef} type="file" accept="image/*,video/*" style={{display:"none"}} onChange={pick} />
        {!prev && (
          <button onClick={()=>fileRef.current?.click()}
            style={{width:"100%",background:"linear-gradient(135deg,#AA00FF,#FF0055)",border:"none",
              borderRadius:14,padding:"clamp(13px,3.5vw,16px)",color:"#fff",
              fontSize:"clamp(13px,3.5vw,15px)",fontWeight:700,fontFamily:"'Orbitron',monospace",
              boxShadow:"0 4px 20px #AA00FF44",display:"flex",alignItems:"center",justifyContent:"center",gap:9}}>
            <span style={{fontSize:"clamp(18px,5vw,22px)"}}>📷</span> ESCOLHER FOTO / VÍDEO
          </button>
        )}
      </div>
    </div>
  );
}
